export default function Greeting({ isLoggedIn }) {
  return (
    <View>
      {isLoggedIn ? (
        <Text>Welcome back! 👋</Text>
      ) : (
        <Text>Please log in. 🔒</Text>
      )}
    </View>
  );
}

